const saved = localStorage.getItem("recipes_final");
if(saved) recipes = JSON.parse(saved);

function save(){
 localStorage.setItem("recipes_final", JSON.stringify(recipes));
}

function render(){
 const q=document.getElementById("search").value.toLowerCase();
 const el=document.getElementById("recipes");
 el.innerHTML="";
 recipes.filter(r=>r.title.toLowerCase().includes(q)).forEach((r,i)=>{
  el.innerHTML+=`
   <div class="card">
    <h2>${r.title}</h2>
    <p>${r.description}</p>
    <button onclick="view($54)">Open</button>
   </div>`;
 });
}

function view(i){
 const r=recipes[i];
 alert(r.title+"\n\n"+r.steps.map(s=>s.title+" ("+s.heat+")\n"+s.body).join("\n\n"));
}

function openAdd(){
 const name=prompt("Recipe name?");
 if(!name)return;
 recipes.push({title:name,description:"Custom",steps:[{title:"Step 1",heat:"",body:""}]});
 save();render();
}

render();
